import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        total = 0
        for _ in range(N):
            x = int(next(it))
            if x % 3 == 0:
                total += x
        out.append(str(total))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

